            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            font-size: 35vw;
            font-weight: 300;
            color: var(--text-primary);
            opacity: 0.03;
            z-index: 0;
            pointer-events: none;
            letter-spacing: -0.05em;
        }

        .error-container {
            position: relative;
            z-index: 10;
            max-width: 500px;
            padding: 40px 24px;
            animation: fadeIn 0.6s ease-out;
        }

        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(20px); }
            to { opacity: 1; transform: translateY(0); }
        }

        h1 {
            font-size: 32px;
            font-weight: 400;
            letter-spacing: -0.02em;
            margin-bottom: 16px;
        }

        p {
            font-size: 15px;
            color: var(--text-secondary);
            font-weight: 300;
            line-height: 1.6;
            margin-bottom: 8px;
        }

        .joke-text {
            font-style: italic;
            color: #8C7B5D;
            margin-bottom: 40px;
        }

        .illustration-wrapper {
            margin-bottom: 32px;
            display: flex;
            justify-content: center;
        }

        .organic-svg {
            width: 80px;
            height: 80px;
        }

        .organic-path {
            fill: none;
            stroke: var(--text-primary);
            stroke-width: 1.5;
            stroke-linecap: round;
            stroke-linejoin: round;
        }

        .actions {
            display: flex;
            gap: 16px;
            justify-content: center;
            margin-bottom: 48px;
            flex-wrap: wrap;
        }

        .btn {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            height: 48px;
            padding: 0 32px;
            font-size: 12px;
            font-weight: 500;
